const items = $input.all();
const validated = [];
const rejected = [];

for (const item of items) {
  try {
    const data = typeof item.json === 'string' ? JSON.parse(item.json) : item.json;
    if (data && typeof data === 'object') {
      validated.push({ json: { ...data, _validated: true } });
    } else {
      rejected.push({ json: { error: 'Not a valid object', raw: item.json } });
    }
  } catch (e) {
    rejected.push({ json: { error: e.message, raw: String(item.json).slice(0, 500) } });
  }
}

return validated.length > 0 ? validated : [{ json: { _empty: true, rejectedCount: rejected.length } }];
